// Create an array of 5 integers using curly braces
int[] scores = {88, 92, 75, 95, 83};
// Variable to hold the sum of all scores
int sum = 0;
// Loop through each element using the length property
for (int i = 0; i < scores.length; i++) {
    // Add each score to the running total
    sum = sum + scores[i];
}
// Calculate average as a double (cast to avoid truncation)
double average = (double) sum / scores.length;
System.out.println("Average score: " + average);
// Expected output:
// Average score: 86.6
